export function getGlossaryPlainParagraphs(
  slug: string,
  fallback: string,
): string[] {
  const expanded = GLOSSARY_PLAIN_EXPLANATIONS[slug];
  if (expanded?.length) return expanded;
  return fallback.split(/\n\n+/).filter(Boolean);
}
